import React, { useState } from 'react';
import { signup } from '../api/api';
import LanguageSwitcher from './LanguageSwitcher';
import Verify from './Verify';

function Signup({ switchToLogin }) {
  const [form, setForm] = useState({ 
    name: '', email: '', password: '', gender: '', age: '', city: '', phone: '' 
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showVerify, setShowVerify] = useState(false);
  const [userData, setUserData] = useState(null);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async () => {
    if (Object.values(form).some(v => !v)) return setError('Tous les champs sont requis');
    setLoading(true);
    setError('');
    try {
      const result = await signup({ ...form, age: parseInt(form.age) });
      setUserData(result.user);
      setShowVerify(true);
      alert('📧 Un code de vérification a été envoyé à votre email et téléphone');
    } catch (err) {
      setError(err.message || 'Erreur');
    } finally {
      setLoading(false);
    }
  };

  if (showVerify && userData) {
    return <Verify 
      user={{ ...userData, phone: form.phone }} 
      onVerified={() => {
        alert('✅ Compte vérifié avec succès!');
        switchToLogin();
      }}
      onBack={() => setShowVerify(false)}
    />;
  }

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>💕 Créer un compte</h1>
        <LanguageSwitcher />
        {['name', 'email', 'password', 'age', 'city', 'phone'].map((field) => (
          <input 
            key={field} 
            name={field} 
            placeholder={
              field === 'name' ? '👤 Nom' : 
              field === 'email' ? '📧 Email' : 
              field === 'password' ? '🔒 Mot de passe' : 
              field === 'age' ? '🎂 Âge' : 
              field === 'city' ? '📍 Ville' : 
              '📱 Téléphone (ex: 0555123456)'
            } 
            value={form[field]} 
            onChange={handleChange} 
            style={styles.input} 
            type={field === 'password' ? 'password' : field === 'age' ? 'number' : 'text'}
          />
        ))}
        <div style={{ display: 'flex', gap: 10 }}>
          <button onClick={() => setForm({ ...form, gender: 'femme' })} style={{ flex: 1, padding: 10, borderRadius: 10, background: form.gender === 'femme' ? '#FF69B4' : '#f0f0f0', color: form.gender === 'femme' ? 'white' : '#333', border: 'none', fontWeight: 'bold' }}>👩 Femme</button>
          <button onClick={() => setForm({ ...form, gender: 'homme' })} style={{ flex: 1, padding: 10, borderRadius: 10, background: form.gender === 'homme' ? '#4A90D9' : '#f0f0f0', color: form.gender === 'homme' ? 'white' : '#333', border: 'none', fontWeight: 'bold' }}>👨 Homme</button>
        </div>
        {error && <p style={styles.error}>{error}</p>}
        <button onClick={handleSubmit} style={styles.button}>{loading ? '⏳...' : '💕 S\'inscrire'}</button>
        <p style={styles.link} onClick={switchToLogin}>🔙 Déjà un compte ?</p>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: 'linear-gradient(135deg, #FFB6C1, #87CEEB)', padding: 20 },
  card: { backgroundColor: 'white', padding: 30, borderRadius: 24, maxWidth: 400, width: '100%', textAlign: 'center' },
  title: { fontSize: '2rem', background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' },
  input: { width: '100%', padding: 12, margin: '8px 0', borderRadius: 12, border: '2px solid #ddd', fontSize: '1rem', boxSizing: 'border-box' },
  button: { width: '100%', padding: 14, background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', border: 'none', borderRadius: 12, fontSize: '1.2rem', fontWeight: 'bold', cursor: 'pointer', marginTop: 10 },
  link: { color: '#4A90D9', cursor: 'pointer', marginTop: 10 },
  error: { color: 'red', fontSize: '0.9rem' },
};

export default Signup;
